import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import logo from '../assets/Logo.png';

const Header = () => {
    const categories = ['Bâtiment', 'Services', 'Fabrication', 'Alimentation'];
    const [searchTerm, setSearchTerm] = useState('');
    const navigate = useNavigate();

    const handleSearch = (e) => {
        e.preventDefault();
        if (searchTerm.trim()) {
            navigate(`/search?q=${searchTerm}`);
            setSearchTerm('');
        }
    };

    return (
        <header className="bg-white shadow-sm mb-4">
            <nav className="navbar navbar-expand-lg navbar-light container py-3">
                <Link className="navbar-brand" to="/">
                    <img
                        src={logo}
                        alt="Trouve ton artisan"
                        style={{ height: "80px", width: "auto" }}
                    />
                </Link>

                <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarNav">
                    <span className="navbar-toggler-icon"></span>
                </button>

                <div className="collapse navbar-collapse" id="navbarNav">
           
                    <ul className="navbar-nav me-auto mb-2 mb-lg-0 ms-lg-4">
                        {categories.map((cat) => (
                            <li className="nav-item" key={cat}>
                                <Link className="nav-link fw-bold text-dark mx-2" to={`/category/${cat}`}>
                                    {cat}
                                </Link>
                            </li>
                        ))}
                    </ul>

                    <form className="d-flex" onSubmit={handleSearch}>
                        <input
                            className="form-control me-2 rounded-pill"
                            type="search"
                            placeholder="Rechercher un artisan..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                        <button 
                            className="btn btn-outline-primary rounded-pill" 
                            type="submit"
                            style={{ borderColor: '#0082c3', color: '#0082c3' }}
                        >
                            Rechercher
                        </button>
                    </form>
                </div>
            </nav>
        </header>
    );
};

export default Header;
